import{_ as e,c as t,o as r,ae as o}from"./chunks/framework.BvcDoAct.js";const M=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ja-jp/Management2/PART2/5.md","filePath":"ja-jp/Management2/PART2/5.md"}'),p={name:"ja-jp/Management2/PART2/5.md"};function n(I,a,E,S,T,s){return r(),t("div",null,[...a[0]||(a[0]=[o('<p>► 2023/01</p><h2 id="_2つ目のボーイズグループ「mazzel」を今作る理由" tabindex="-1">2つ目のボーイズグループ「MAZZEL」を今作る理由 <a class="header-anchor" href="#_2つ目のボーイズグループ「mazzel」を今作る理由" aria-label="Permalink to &quot;2つ目のボーイズグループ「MAZZEL」を今作る理由&quot;">​</a></h2><p>#新プロジェクト #Mx2 #MAZZEL #焦り #迷路の抜け道 #幸せ</p><h3 id="「もう本当にめちゃくちゃ焦っていました。物事ってやると動くけど、やらないと動かないじゃないですか。やらないと進まないから」" tabindex="-1">「もう本当にめちゃくちゃ焦っていました。物事ってやると動くけど、やらないと動かないじゃないですか。やらないと進まないから」 <a class="header-anchor" href="#「もう本当にめちゃくちゃ焦っていました。物事ってやると動くけど、やらないと動かないじゃないですか。やらないと進まないから」" aria-label="Permalink to &quot;「もう本当にめちゃくちゃ焦っていました。物事ってやると動くけど、やらないと動かないじゃないですか。やらないと進まないから」&quot;">​</a></h3><p><strong>SKY-HIが率いるBMSGの2つ目のダンス&amp;ボーカルグループ「MAZZEL(マーゼル)」の誕生を追ったオーディションドキュメンタリー番組「MISSIONx2」(以下、「Mx2」)が配信中だ。</strong></p><p><strong>BE:FIRSTが誕生したオーディション「THE FIRST」後にトレーニーとなったRANとREIKOは、オーディション後に様々な活動を行ってきた。RANは21年9月・10月、22年1月に舞台「絶対青春合唱コメディ『SING!!!』で主演を務め、REIKOは21年10月にSKY-HIの『One More Day feat.REIKO』に参加。彼はSKY-HIと共に『スッキリ』にも出演し、その後、SKY-HIのホールツアー『SKY-HI HALL TOUR 2022-八面六臂-』9公演に帯同した。21年11月・12月には2人そろってファッションブランド・TOMMY HILFIGERのトークイベントへ出演、22年1月には「THE FIRST」の締めくくりとなるライブ「THE FIRST FINAL」にも出演した。「Mx2」の1話はそれらの活動が一段落した4月から始まった。</strong></p><p><strong>こうして時系列で考えると、改めてTHE FIRST以降、BE:FIRSTだけでなく2つ目のグループへの動きも相当なスピード感だったことがうかがえる。MAZZELのデビューに関してSKY-HIは「もう本当にめちゃくちゃ焦っていました」と語る。</strong></p><p>繰り返しになりますが、REIKOには元々ソロアーティストなのかグループのメンバーなのか、いろいろな可能性があったので、僕のツアーのオープニングアクトとして帯同するのは絶対にやらせてほしく、スタッフにも無理を言いました。そうした個別の活動を進めながら、そうでない時間はみんなと一緒に練習もしてもらい、4月に「Mx2」が正式に始動しましたね。</p><p>いやあ、もう本当にめちゃくちゃ焦っていました。物事ってやると動くけど、やらないと動かないじゃないですか。やらないと進まない。だからセカンドグループのための子たちも早く集めたかったし。実際はREIKOやAile The Shotaと『スッキリ』に出た21年10月にはセカンドグループの構想を発表したかったんですよ。でも、BE:FIRSTのプレデビューがようやくうまくいき、これからデビューという微妙なタイミング。いろんな方面から反対の声もあって「そうか」と思って止めましたが、そのくらい焦っていました(笑)。ならば、年が明けた1月の「THE FIRST FINAL」で発表しようかなと思ったんですが、その頃にはKAIRYUとSEITOがトレーニーで入ってくれていたので、いろいろ方向性を変えながら・・・22年も本当に焦っていたんですが、冷静に状況を見つつプログラム終了を見届け、結成していることを含めて11月に発表し、第1話でメンバーを全員を映すという方針を決定しました。</p><p><strong>BMSGのような設立3年目で決して規模の大きくない会社が同時にボーイズグループを2つ走らせることは簡単ではないはずだ。それでも、今やることの意味は大きい。</strong></p><p>自分がやりたいことは既存のシステムそのものを変えることなので、「いろんな形のグループがある」ことは本当に大事なんです。BE:FIRSTとMAZZELのクリエーティブは全く違うものにしたいと全社で前向きに取り組んでいます。まだBEFIRSTでもやりきれてない「こんな日本のボーイズグループがかっこいいよね」がいっぱいあります。でも、トンマナ(トーン&amp;マナー/イメージの統一性貫性を保つためのルール)は大事にしたい。今のBE:FIRSTがMAZZELっぽいことをするわけにはいきませんから。</p><p>ただ、現時点では「THE FIRST」に共感共鳴したり、BE:FIRSTと僕の関わりを見て応募してくれる方が少なくなく、「Mx2」やMAZZELは違ったものになるので、そこに少し難しさがあるなと感じています。「MAZZELっぽさ」が何かは気になるところでしょう。でも、それを言語化すると凝り固まったイメージが生じてしまうので、今後のMAZZELをご覧いただくのが1番だと思います。</p><p>複数グループが活動したほうがいいもう1つの目的が、今後の「BMSG FES」でワクワクし続けられる環境を作ること。昨年のフエスで、NovelCoreと僕の会場への思いだったり、「THE FIRST」からの15人のストーリーはいったん完結しているから、次の章に進まなくてはいけません。かっこいいグループが1つあり、別のかっこいいグループも1つあり、かっこいい複数のグループの人たちが有機的に重なり合っていく...それをすごくやりたいんです。本当はよその事務所も絡めてやっていきたいけれども、自社だけでもそれができる状況を作りたいという感じかな。</p>',13)])])}const _=e(p,[["render",n]]);export{M as __pageData,_ as default};
